"""
Parameterized generator for GH1205_FLAML_1470.

Source PR:    https://github.com/microsoft/FLAML/pull/1470
Source Issue: N/A

Seed varies: renames 'append' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1205_FLAML_1470'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1205_FLAML_1470'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('append', 'append' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1205_FLAML_1470',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'microsoft/FLAML',
                "pr_number": 1470,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/microsoft/FLAML/pull/1470",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'flaml/default/estimator.py': 'from functools import wraps\n\nfrom flaml.automl.task.task import CLASSIFICATION\n\nfrom .suggest import preprocess_and_suggest_hyperparams\n\nDEFAULT_LOCATION = "default_location"\n\n\ndef flamlize_estimator(super_class, name: str, task: str, alternatives=None):\n    """Enhance an estimator class with flaml\'s data-dependent default hyperparameter settings.\n\n    Example:\n\n    ```python\n    import sklearn.ensemble as ensemble\n    RandomForestRegressor = flamlize_estimator(\n        ensemble.RandomForestRegressor, "rf", "regression"\n    )\n    ```\n\n    Args:\n        super_class: an scikit-learn compatible estimator class.\n        name: a str of the estimator\'s name.\n        task: a str of the task type.\n        alternatives: (Optional) a list for alternative estimator names. For example,\n            ```[("max_depth", 0, "xgboost")]``` means if the "max_depth" is set to 0\n            in the constructor, then look for the learned defaults for estimator "xgboost".\n    """\n\n    class EstimatorClass(super_class):\n        """**Enhanced with flaml\'s data-dependent default hyperparameter settings.**"""\n\n        @wraps(super_class.__init__)\n        def __init__(self, **params):\n            if DEFAULT_LOCATION in params:\n                self._default_location = params.pop(DEFAULT_LOCATION)\n            else:\n                self._default_location = None\n            self._params = params\n            super().__init__(**params)\n\n        # @classmethod\n        # @wraps(super_class._get_param_names)\n        # def _get_param_names(cls):\n        #     return super_class._get_param_names() if hasattr(super_class, "_get_param_names") else []\n\n        def suggest_hyperparams(self, X, y):\n            """Suggest hyperparameters.\n\n            Example:\n\n            ```python\n            from flaml.default import LGBMRegressor\n\n            estimator = LGBMRegressor()\n            hyperparams, estimator_name, X_transformed, y_transformed = estimator.fit(X_train, y_train)\n            print(hyperparams)\n            ```\n\n            Args:\n                X: A dataframe of training data in shape n*m.\n                y: A series of labels in shape n*1.\n\n            Returns:\n                hyperparams: A dict of the hyperparameter configurations.\n                estimator_name: A str of the underlying estimator name, e.g., \'xgb_limitdepth\'.\n                X_transformed: the preprocessed X.\n                y_transformed: the preprocessed y.\n            """\n            estimator_name = name\n            if alternatives:\n                for alternative in alternatives:\n                    if self._params.get(alternative[0]) == alternative[1]:\n                        estimator_name = alternative[2]\n                        break\n            estimator_name = (\n                "choose_xgb"\n                if (estimator_name == "xgb_limitdepth" and "max_depth" not in self._params)\n                else estimator_name\n            )\n            (\n                hyperparams,\n                estimator_class,\n                X_transformed,\n                y_transformed,\n                self._feature_transformer,\n                self._label_transformer,\n            ) = preprocess_and_suggest_hyperparams(task, X, y, estimator_name, self._default_location)\n            assert estimator_class == super_class\n            hyperparams.update(self._params)\n            return hyperparams, estimator_name, X_transformed, y_transformed\n\n        @wraps(super_class.fit)\n        def fit(self, X, y, *args, **params):\n            hyperparams, estimator_name, X, y_transformed = self.suggest_hyperparams(X, y)\n            self.set_params(**hyperparams)\n            if self._label_transformer and estimator_name in [\n                "rf",\n                "extra_tree",\n                "xgboost",\n                "xgb_limitdepth",\n                "choose_xgb",\n            ]:\n                # rf and et have trouble in handling boolean labels; xgboost requires integer labels\n                fitted = super().fit(X, y_transformed, *args, **params)\n                # if hasattr(self, "_classes"):\n                #     self._classes = self._label_transformer.classes_\n                # else:\n                try:\n                    self.classes_ = self._label_transformer.classes_\n                except AttributeError:\n                    # xgboost 2: AttributeError: can\'t set attribute\n                    if "xgb" not in estimator_name:\n                        raise\n                if "xgb" not in estimator_name:\n                    # rf and et would do inverse transform automatically; xgb doesn\'t\n                    self._label_transformer = None\n            else:\n                # lgbm doesn\'t need label transformation except for non-str/num labels\n                try:\n                    fitted = super().fit(X, y, *args, **params)\n                    self._label_transformer = None\n                except ValueError:\n                    # Unknown label type: \'unknown\'\n                    fitted = super().fit(X, y_transformed, *args, **params)\n                    self._classes = self._label_transformer.classes_\n            return fitted\n\n        @wraps(super_class.predict)\n        def predict(self, X, *args, **params):\n            if name != "lgbm" or task not in CLASSIFICATION:\n                X = self._feature_transformer.transform(X)\n            y_pred = super().predict(X, *args, **params)\n            if self._label_transformer and y_pred.ndim == 1:\n                y_pred = self._label_transformer.inverse_transform(y_pred)\n            return y_pred\n\n        if hasattr(super_class, "predict_proba"):\n\n            @wraps(super_class.predict_proba)\n            def predict_proba(self, X, *args, **params):\n                X_test = self._feature_transformer.transform(X)\n                y_pred = super().predict_proba(X_test, *args, **params)\n                return y_pred\n\n    EstimatorClass.__doc__ += " " + super_class.__doc__\n    EstimatorClass.__name__ = super_class.__name__\n    return EstimatorClass\n\n\ntry:\n    import sklearn.ensemble as ensemble\nexcept ImportError:\n    RandomForestClassifier = RandomForestRegressor = ExtraTreesClassifier = ExtraTreesRegressor = ImportError(\n        "Using flaml.default.* requires scikit-learn."\n    )\nelse:\n    RandomForestRegressor = flamlize_estimator(ensemble.RandomForestRegressor, "rf", "regression")\n    RandomForestClassifier = flamlize_estimator(ensemble.RandomForestClassifier, "rf", "classification")\n    ExtraTreesRegressor = flamlize_estimator(ensemble.ExtraTreesRegressor, "extra_tree", "regression")\n    ExtraTreesClassifier = flamlize_estimator(ensemble.ExtraTreesClassifier, "extra_tree", "classification")\n\ntry:\n    import lightgbm\nexcept ImportError:\n    LGBMRegressor = LGBMClassifier = ImportError("Using flaml.default.LGBM* requires lightgbm.")\nelse:\n    LGBMRegressor = flamlize_estimator(lightgbm.LGBMRegressor, "lgbm", "regression")\n    LGBMClassifier = flamlize_estimator(lightgbm.LGBMClassifier, "lgbm", "classification")\n\ntry:\n    import xgboost\nexcept ImportError:\n    XGBClassifier = XGBRegressor = ImportError("Using flaml.default.XGB* requires xgboost.")\nelse:\n    XGBRegressor = flamlize_estimator(\n        xgboost.XGBRegressor,\n        "xgb_limitdepth",\n        "regression",\n        [("max_depth", 0, "xgboost")],\n    )\n    XGBClassifier = flamlize_estimator(\n        xgboost.XGBClassifier,\n        "xgb_limitdepth",\n        "classification",\n        [("max_depth", 0, "xgboost")],\n    )\n    # if hasattr(xgboost.XGBRegressor, "_get_param_names"):\n    #     XGBRegressor._get_param_names = xgboost.XGBRegressor._get_param_names\n    #     XGBClassifier._get_param_names = xgboost.XGBClassifier._get_param_names\n',
            'test/default/test_defaults.py': 'import pickle\nimport sys\n\nimport pandas as pd\nfrom sklearn.datasets import fetch_california_housing, load_breast_cancer, load_iris\nfrom sklearn.model_selection import train_test_split\n\nfrom flaml import AutoML\nfrom flaml.default import (\n    portfolio,\n    preprocess_and_suggest_hyperparams,\n    regret,\n    suggest_hyperparams,\n    suggest_learner,\n)\n\n\ndef test_greedy_feedback(path="test/default", strategy="greedy-feedback"):\n    # sys.argv = f"portfolio.py --output {path} --input {path} --metafeatures {path}/all/metafeatures.csv --task binary --estimator lgbm xgboost xgb_limitdepth rf extra_tree --strategy {strategy}".split()\n    # portfolio.main()\n    # sys.argv = f"portfolio.py --output {path} --input {path} --metafeatures {path}/all/metafeatures.csv --task multiclass --estimator lgbm xgboost xgb_limitdepth rf extra_tree --strategy {strategy}".split()\n    # portfolio.main()\n    sys.argv = f"portfolio.py --output {path} --input {path} --metafeatures {path}/all/metafeatures.csv --task regression --estimator lgbm --strategy {strategy}".split()\n    portfolio.main()\n\n\ndef test_build_portfolio(path="test/default", strategy="greedy"):\n    sys.argv = f"portfolio.py --output {path} --input {path} --metafeatures {path}/all/metafeatures.csv --task binary --estimator lgbm xgboost xgb_limitdepth rf extra_tree --strategy {strategy}".split()\n    portfolio.main()\n    sys.argv = f"portfolio.py --output {path} --input {path} --metafeatures {path}/all/metafeatures.csv --task multiclass --estimator lgbm xgboost xgb_limitdepth rf extra_tree --strategy {strategy}".split()\n    portfolio.main()\n    sys.argv = f"portfolio.py --output {path} --input {path} --metafeatures {path}/all/metafeatures.csv --task regression --estimator lgbm xgboost xgb_limitdepth rf extra_tree --strategy {strategy}".split()\n    portfolio.main()\n\n\ndef test_iris(as_frame=True):\n    automl = AutoML()\n    automl_settings = {\n        "time_budget": 2,\n        "metric": "accuracy",\n        "task": "classification",\n        "log_file_name": "test/iris.log",\n        "n_jobs": 1,\n        "starting_points": "data",\n    }\n    X_train, y_train = load_iris(return_X_y=True, as_frame=as_frame)\n    automl.fit(X_train, y_train, **automl_settings)\n    automl_settings["starting_points"] = "data:test/default"\n    automl.fit(X_train, y_train, **automl_settings)\n\n\ndef test_housing(as_frame=True):\n    automl = AutoML()\n    automl_settings = {\n        "time_budget": 2,\n        "task": "regression",\n        "estimator_list": ["xgboost", "lgbm"],\n        "log_file_name": "test/housing.log",\n        "n_jobs": 1,\n        "starting_points": "data",\n        "max_iter": 0,\n    }\n    X_train, y_train = fetch_california_housing(return_X_y=True, as_frame=as_frame, data_home="test")\n    automl.fit(X_train, y_train, **automl_settings)\n\n\ndef test_regret():\n    sys.argv = "regret.py --result_csv test/default/lgbm/results.csv --task_type binary --output test/default/lgbm/binary_regret.csv".split()\n    regret.main()\n\n\ndef test_suggest_classification():\n    location = "test/default"\n    X_train, y_train = load_breast_cancer(return_X_y=True, as_frame=True)\n    suggested = suggest_hyperparams("classification", X_train, y_train, "lgbm", location=location)\n    print(suggested)\n    suggested = preprocess_and_suggest_hyperparams("classification", X_train, y_train, "xgboost", location=location)\n    print(suggested)\n    suggested = suggest_hyperparams("classification", X_train, y_train, "xgb_limitdepth", location=location)\n    print(suggested)\n\n    X, y = load_iris(return_X_y=True, as_frame=True)\n    X_train, X_test, y_train, y_test = train_test_split(X, y, test_size=0.33, random_state=42)\n    (\n        hyperparams,\n        estimator_class,\n        X,\n        y,\n        feature_transformer,\n        label_transformer,\n    ) = preprocess_and_suggest_hyperparams("classification", X_train, y_train, "lgbm", location=location)\n    with open("test/default/feature_transformer", "wb") as f:\n        pickle.dump(feature_transformer, f, pickle.HIGHEST_PROTOCOL)\n    model = estimator_class(**hyperparams)  # estimator_class is LGBMClassifier\n    model.fit(X, y)\n    X_test = feature_transformer.transform(X_test)\n    y_pred = label_transformer.inverse_transform(pd.Series(model.predict(X_test).astype(int)))\n    print(y_pred)\n    suggested = suggest_hyperparams("classification", X_train, y_train, "xgboost", location=location)\n    print(suggested)\n    suggested = preprocess_and_suggest_hyperparams(\n        "classification", X_train, y_train, "xgb_limitdepth", location=location\n    )\n    print(suggested)\n    suggested = suggest_hyperparams("classification", X_train, y_train, "xgb_limitdepth", location=location)\n    suggested = suggest_learner(\n        "classification",\n        X_train,\n        y_train,\n        estimator_list=["xgboost", "xgb_limitdepth"],\n        location=location,\n    )\n    print(suggested)\n\n\ndef test_suggest_regression():\n    location = "test/default"\n    X_train, y_train = fetch_california_housing(return_X_y=True, as_frame=True, data_home="test")\n    suggested = suggest_hyperparams("regression", X_train, y_train, "lgbm", location=location)\n    print(suggested)\n    suggested = preprocess_and_suggest_hyperparams("regression", X_train, y_train, "xgboost", location=location)\n    print(suggested)\n    suggested = suggest_hyperparams("regression", X_train, y_train, "xgb_limitdepth", location=location)\n    print(suggested)\n    suggested = suggest_learner("regression", X_train, y_train, location=location)\n    print(suggested)\n\n\ndef test_rf():\n    from flaml.default import RandomForestClassifier, RandomForestRegressor\n\n    X_train, y_train = load_breast_cancer(return_X_y=True, as_frame=True)\n    rf = RandomForestClassifier()\n    rf.fit(X_train[:100], y_train[:100])\n    rf.predict(X_train)\n    rf.predict_proba(X_train)\n    print(rf)\n\n    location = "test/default"\n    X_train, y_train = fetch_california_housing(return_X_y=True, as_frame=True, data_home="test")\n    rf = RandomForestRegressor(default_location=location)\n    rf.fit(X_train[:100], y_train[:100])\n    rf.predict(X_train)\n    print(rf)\n\n\ndef test_extratrees():\n    from flaml.default import ExtraTreesClassifier, ExtraTreesRegressor\n\n    X_train, y_train = load_iris(return_X_y=True, as_frame=True)\n    classifier = ExtraTreesClassifier()\n    classifier.fit(X_train[:100], y_train[:100])\n    classifier.predict(X_train)\n    classifier.predict_proba(X_train)\n    print(classifier)\n\n    location = "test/default"\n    X_train, y_train = fetch_california_housing(return_X_y=True, as_frame=True, data_home="test")\n    regressor = ExtraTreesRegressor(default_location=location)\n    regressor.fit(X_train[:100], y_train[:100])\n    regressor.predict(X_train)\n    print(regressor)\n\n\ndef test_lgbm():\n    from flaml.default import LGBMClassifier, LGBMRegressor\n\n    X_train, y_train = load_breast_cancer(return_X_y=True, as_frame=True)\n    classifier = LGBMClassifier(n_jobs=1)\n    classifier.fit(X_train, y_train)\n    classifier.predict(X_train, pred_contrib=True)\n    classifier.predict_proba(X_train)\n    print(classifier.get_params())\n    print(classifier)\n    print(classifier.classes_)\n\n    location = "test/default"\n    X_train, y_train = fetch_california_housing(return_X_y=True, as_frame=True, data_home="test")\n    regressor = LGBMRegressor(default_location=location)\n    regressor.fit(X_train, y_train)\n    regressor.predict(X_train)\n    print(regressor)\n\n\ndef test_xgboost():\n    from flaml.default import XGBClassifier, XGBRegressor\n\n    X_train, y_train = load_breast_cancer(return_X_y=True, as_frame=True)\n    classifier = XGBClassifier(max_depth=0)\n    classifier.fit(X_train[:100], y_train[:100])\n    classifier.predict(X_train)\n    classifier.predict_proba(X_train)\n    print(classifier)\n    print(classifier.classes_)\n\n    location = "test/default"\n    X_train, y_train = fetch_california_housing(return_X_y=True, as_frame=True, data_home="test")\n    regressor = XGBRegressor(default_location=location)\n    regressor.fit(X_train[:100], y_train[:100])\n    regressor.predict(X_train)\n    print(regressor)\n\n\ndef test_nobudget():\n    X_train, y_train = load_breast_cancer(return_X_y=True, as_frame=True)\n    automl = AutoML()\n    automl.fit(\n        X_train[:20],\n        y_train[:20],\n        estimator_list=["lgbm", "extra_tree", "rf"],\n        max_iter=12,\n        starting_points="data",\n        log_file_name="test/default/no_budget.txt",\n        log_type="all",\n    )\n    automl.fit(X_train[:20], y_train[:20], estimator_list=["lgbm", "extra_tree", "rf"])\n    # make sure that zero-shot config out of the search space does not degnerate to low cost init config\n    assert automl.best_config_per_estimator["extra_tree"]["n_estimators"] > 4\n    # make sure that the zero-shot config {} is not modified\n    assert "criterion" not in automl.best_config_per_estimator["rf"]\n\n\nif __name__ == "__main__":\n    test_build_portfolio("flaml/default")\n',
        }
